-- Winline CDP Cohort: deposit_and_mission
-- Generated: 2026-04-22 | 13,819 user IDs from Snowflake CDP
-- Paste into BQ console and run

WITH enriched AS (
  SELECT
    u.user_id,
    'deposit_and_mission' AS cohort,
    u.last_match_created_at,
    u.last_login_at,
    u.last_active_date,
    u.country_iso_code,
    u.last_country_iso_code,
    u.settings_language,
    u.has_premium_subscription,
    u.has_platform_subscription,
    u.is_verified,
    u.face_verification_status,
    u.id_verification_status,
    u.registration_status,
    u.age_tier,
    u.created_at,

    CASE
      WHEN u.last_match_created_at >= TIMESTAMP_SUB(CURRENT_TIMESTAMP(), INTERVAL 30 DAY)
        THEN '1_active_30d'
      WHEN u.last_match_created_at >= TIMESTAMP_SUB(CURRENT_TIMESTAMP(), INTERVAL 60 DAY)
        THEN '2_recent_60d'
      WHEN u.last_match_created_at >= TIMESTAMP_SUB(CURRENT_TIMESTAMP(), INTERVAL 90 DAY)
        THEN '3_lapsing_90d'
      WHEN u.last_match_created_at >= TIMESTAMP_SUB(CURRENT_TIMESTAMP(), INTERVAL 180 DAY)
        THEN '4_dormant_180d'
      WHEN u.last_match_created_at >= TIMESTAMP_SUB(CURRENT_TIMESTAMP(), INTERVAL 365 DAY)
        THEN '5_churned_1y'
      WHEN u.last_match_created_at IS NOT NULL
        THEN '6_gone_over_1y'
      ELSE '7_never_matched'
    END AS match_recency_bucket

  FROM `business-intelligence-prod.dbt_user.dim__users` u
