SELECT
  cohort,
  match_recency_bucket,
  COUNT(*) AS users,
  ROUND(COUNT(*) * 100.0 / SUM(COUNT(*)) OVER (), 1) AS pct_of_cohort,

  COUNTIF(has_premium_subscription) AS premium_users,
  ROUND(COUNTIF(has_premium_subscription) * 100.0 / COUNT(*), 1) AS pct_premium,
  COUNTIF(has_platform_subscription) AS platform_sub_users,

  COUNTIF(is_verified) AS verified_users,
  ROUND(COUNTIF(is_verified) * 100.0 / COUNT(*), 1) AS pct_verified,
  COUNTIF(face_verification_status = 'COMPLETED') AS face_verified,
  COUNTIF(id_verification_status = 'COMPLETED') AS id_verified,

  COUNTIF(last_login_at >= TIMESTAMP_SUB(CURRENT_TIMESTAMP(), INTERVAL 30 DAY)) AS logged_in_30d,

  APPROX_TOP_COUNT(COALESCE(last_country_iso_code, country_iso_code), 3) AS top_countries,
  APPROX_TOP_COUNT(age_tier, 3) AS top_age_tiers,
  APPROX_TOP_COUNT(settings_language, 3) AS top_languages,

  APPROX_QUANTILES(DATE_DIFF(CURRENT_DATE(), DATE(created_at), DAY), 100)[OFFSET(50)] AS median_account_age_days

FROM enriched
GROUP BY cohort, match_recency_bucket
ORDER BY match_recency_bucket
